#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    const char *path = "/tmp/kf_redirect.txt";
    int saved_stdout = dup(STDOUT_FILENO);
    int fd = open(path, O_CREAT | O_WRONLY | O_TRUNC, 0644);
    dup2(fd, STDOUT_FILENO);
    close(fd);
    printf("redirected output");
    fflush(stdout);
    dup2(saved_stdout, STDOUT_FILENO);
    close(saved_stdout);
    int rfd = open(path, O_RDONLY);
    char buf[64];
    ssize_t n = read(rfd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    close(rfd);
    printf("Captured: %s\n", buf);
    unlink(path);
    return 0;
}

